input.card_css:
.globe-container {
  width: 100%;
  height: 100%;
  position: relative;
  overflow: hidden;
  background: #000;
}

#globe-canvas {
  width: 100%;
  height: 100%;
  display: block;
}

.loading-overlay {
  position: absolute;
  top: 0; left: 0; right: 0; bottom: 0;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  background: rgba(0, 0, 0, 0.7);
  color: #fff;
  z-index: 10;
  transition: opacity 0.5s ease;
}

.loading-overlay.hidden {
  opacity: 0;
  pointer-events: none;
}

.spinner {
  width: 40px;
  height: 40px;
  border: 3px solid rgba(255, 255, 255, 0.3);
  border-top-color: #4a9eff;
  border-radius: 50%;
  animation: spin 1s linear infinite;
}

@keyframes spin {
  to { transform: rotate(360deg); }
}

.loading-overlay p {
  margin-top: 12px;
  font-size: 14px;
  color: #aaa;
}

.news-overlay {
  position: absolute;
  top: 20px;
  right: 20px;
  z-index: 20;
  opacity: 0;
  pointer-events: none;
  transition: opacity 0.3s ease;
}

.news-overlay.visible {
  opacity: 1;
  pointer-events: auto;
}

.news-card {
  background: rgba(10, 15, 30, 0.95);
  border: 1px solid rgba(74, 158, 255, 0.4);
  border-radius: 12px;
  padding: 20px;
  width: 340px;
  max-height: 400px;
  overflow-y: auto;
  color: #e0e0e0;
  backdrop-filter: blur(10px);
  box-shadow: 0 8px 32px rgba(0, 0, 0, 0.6);
}

.close-btn {
  position: absolute;
  top: 8px;
  right: 12px;
  background: none;
  border: none;
  color: #888;
  font-size: 22px;
  cursor: pointer;
  line-height: 1;
  padding: 4px;
}

.close-btn:hover {
  color: #fff;
}

.news-headline {
  font-size: 17px;
  font-weight: 600;
  margin: 0 0 10px 0;
  line-height: 1.4;
  color: #fff;
}

.news-meta {
  display: flex;
  gap: 12px;
  font-size: 12px;
  color: #888;
  margin-bottom: 12px;
}

.news-description {
  font-size: 14px;
  line-height: 1.5;
  color: #bbb;
  margin: 0 0 14px 0;
}

.news-link {
  display: inline-block;
  color: #4a9eff;
  text-decoration: none;
  font-size: 14px;
  font-weight: 500;
}

.news-link:hover {
  text-decoration: underline;
}

.legend {
  position: absolute;
  bottom: 20px;
  left: 20px;
  z-index: 20;
  display: flex;
  gap: 14px;
  background: rgba(10, 15, 30, 0.8);
  border: 1px solid rgba(255, 255, 255, 0.1);
  border-radius: 8px;
  padding: 8px 14px;
}

.legend-item {
  display: flex;
  align-items: center;
  gap: 6px;
  font-size: 11px;
  color: #aaa;
  white-space: nowrap;
}

.legend-dot {
  width: 8px;
  height: 8px;
  border-radius: 50%;
  display: inline-block;
}

.legend-dot.breaking { background: #ff4444; }
.legend-dot.tech { background: #4a9eff; }
.legend-dot.science { background: #44cc44; }
.legend-dot.business { background: #ffcc00; }
.legend-dot.other { background: #888; }

