// RSS Globe — Three.js 3D globe with RSS news markers
(function() {
  'use strict';

  // --- Location mapping table ---
  var locationMap = [
    { keywords: ['usa', 'united states', 'washington', 'new york', 'california', 'texas'], lat: 39.0, lng: -98.0 },
