// RSS Globe — Three.js 3D globe with RSS news markers
(function() {
  'use strict';

  var scene, camera, renderer, globe, markers = [];
  var raycaster, mouse;
  var newsItems = [];
  var clock;
  var overlayEl, loadingEl;
  var rootEl;

  function init() {
    clock = new THREE.Clock();
    rootEl = document.createElement('div');
    rootEl.className = 'globe-container';
    rootEl.innerHTML = document.querySelector('.globe-container') ? '' : '';
    // Append to body since CARD_SHIM handles placement
    document.body.appendChild(rootEl);

    var canvasEl = document.createElement('canvas');
    canvasEl.id = 'globe-canvas';
    rootEl.appendChild(canvasEl);

    // Create overlay elements
    rootEl.innerHTML = `
      <canvas id="globe-canvas"></canvas>
      <div class="loading-overlay" id="loading-overlay">
        <div class="spinner"></div>
        <p>Loading globe...</p>
      </div>
      <div class="news-overlay" id="news-overlay">
        <div class="news-card">
          <button class="close-btn" id="close-news">&times;</button>
          <h2 class="news-headline" id="news-headline"></h2>
          <div class="news-meta">
            <span class="news-source" id="news-source"></span>
            <span class="news-date" id="news-date"></span>
          </div>
          <p class="news-description" id="news-description"></p>
          <a class="news-link" id="news-link" href="#" target="_blank" rel="noopener">Open article →</a>
        </div>
      </div>
      <div class="legend" id="legend">
        <div class="legend-item"><span class="legend-dot breaking"></span> Breaking</div>
        <div class="legend-item"><span class="legend-dot tech"></span> Tech</div>
        <div class="legend-item"><span class="legend-dot science"></span> Science</div>
        <div class="legend-item"><span class="legend-dot business"></span> Business</div>
