var categoryColors = {
  breaking: 0xff4444,
  tech: 0x4a9eff,
  science: 0x44cc44,
  business: 0xffcc00,
  other: 0x888888
};

var categoryKeywords = {
  breaking: ['urgent', 'crisis', 'emergency', 'alert', 'breaking', 'shooting', 'attack', 'disaster', 'earthquake', 'storm', 'war', 'conflict'],
  tech: ['tech', 'software', 'ai', 'startup', 'apple', 'google', 'microsoft', 'meta', 'tesla', 'cyber', 'digital', 'app', 'device', 'chip'],
  science: ['science', 'space', 'nasa', 'discovery', 'research', 'medical', 'health', 'biology', 'climate', 'environment', 'discovery'],
  business: ['market', 'stock', 'economy', 'finance', 'trade', 'bank', 'wall street', 'recession', 'inflation', 'gdp', 'earnings', 'ipo']
};

function detectCategory(title, description) {
  var text = (title || '') + ' ' + (description || '');
  text = text.toLowerCase();
  for (var cat in categoryKeywords) {
    for (var i = 0; i < categoryKeywords[cat].length; i++) {
      if (text.indexOf(categoryKeywords[cat][i]) !== -1) return cat;
    }
  }
  return 'other';
}

function findLocation(title, description, source) {
  var text = (title || '') + ' ' + (description || '') + ' ' + (source || '');
  text = text.toLowerCase();
  var best = null;
  var bestScore = -1;
  for (var i = 0; i < locationMap.length; i++) {
    var score = 0;
    for (var j = 0; j < locationMap[i].keywords.length; j++) {
      if (text.indexOf(locationMap[i].keywords[j]) !== -1) {
        score += locationMap[i].keywords[j].length;
      }
    }
    if (score > bestScore) {
      bestScore = score;
      best = locationMap[i];
    }
  }
  return bestScore > 0 ? best : { lat: 20, lng: 0 };
}

function latLngToVec3(lat, lng, radius) {
  var phi = (90 - lat) * (Math.PI / 180);
  var theta = (lng + 180) * (Math.PI / 180);
  var x = -(radius * Math.sin(phi) * Math.cos(theta));
  var y = (radius * Math.cos(phi));
  var z = (radius * Math.sin(phi) * Math.sin(theta));
  return new THREE.Vector3(x, y, z);
}

// --- State ---
var scene, camera, renderer, globe, markers = [];
var raycaster, mouse;
var newsItems = [];
var clock;
var overlayEl, loadingEl;

async function init() {
  clock = new THREE.Clock();

  overlayEl = container.querySelector('#news-overlay');
  loadingEl = container.querySelector('#loading-overlay');

  scene = new THREE.Scene();

  // Camera
  camera = new THREE.PerspectiveCamera(45, 1, 0.1, 1000);
  camera.position.z = 3.2;

  // Renderer
  var canvasEl = container.querySelector('#globe-canvas');
  renderer = new THREE.WebGLRenderer({ canvas: canvasEl, antialias: true, alpha: false });
  renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
  renderer.setClearColor(0x000000, 1);

  // Stars
  createStars();

  // Globe
  createGlobe();

  // Lights
  var ambientLight = new THREE.AmbientLight(0x333333, 1.5);
  scene.add(ambientLight);
  var directionalLight = new THREE.DirectionalLight(0xffffff, 1.2);
  directionalLight.position.set(5, 3, 5);
  scene.add(directionalLight);

  // Raycaster
  raycaster = new THREE.Raycaster();
  mouse = new THREE.Vector2();

  // Events
  canvasEl.addEventListener('click', onCanvasClick, false);
  canvasEl.addEventListener('mousemove', onCanvasHover, false);

  // Close button
  container.querySelector('#close-news').addEventListener('click', function() {
    overlayEl.classList.remove('visible');
  });

  // Start
  updateSize();
  window.addEventListener('resize', onWindowResize, false);

  fetchAndParseFeeds();
  setInterval(fetchAndParseFeeds, 3600000); // hourly

  animate();
}

function createStars() {
  var starsGeo = new THREE.BufferGeometry();
  var starPositions = [];
  for (var i = 0; i < 2000; i++) {
    starPositions.push(
      (Math.random() - 0.5) * 100,
      (Math.random() - 0.5) * 100,
      (Math.random() - 0.5) * 100
    );
  }
  starsGeo.setAttribute('position', new THREE.Float32BufferAttribute(starPositions, 3));
  var starsMat = new THREE.PointsMaterial({ color: 0xffffff, size: 0.05, sizeAttenuation: true });
  var stars = new THREE.Points(starsGeo, starsMat);
  scene.add(stars);
}

function createGlobe() {
  var globeGroup = new THREE.Group();

  // Earth sphere
  var sphereGeo = new THREE.SphereGeometry(1, 64, 64);
  var textureLoader = new THREE.TextureLoader();
  var earthTexture = textureLoader.load('https://cdn.jsdelivr.net/gh/mrdoob/three.js@r160/examples/textures/planets/earth_atmos_2048.jpg');
  var earthMat = new THREE.MeshPhongMaterial({
    map: earthTexture,
    specular: 0x333333,
    shininess: 5,
    ambient: 0x555555
  });
  var earthMesh = new THREE.Mesh(sphereGeo, earthMat);
  globeGroup.add(earthMesh);

  // Atmosphere glow
  var atmosGeo = new THREE.SphereGeometry(1.015, 64, 64);
  var atmosMat = new THREE.MeshPhongMaterial({
    color: 0x4a9eff,
    transparent: true,
    opacity: 0.08,
    side: THREE.FrontSide
  });
  var atmosMesh = new THREE.Mesh(atmosGeo, atmosMat);
  globeGroup.add(atmosMesh);

  // Grid lines
  var gridMat = new THREE.LineBasicMaterial({ color: 0xffffff, transparent: true, opacity: 0.06 });
  for (var i = 0; i < 12; i++) {
    var angle = (i / 12) * Math.PI * 2;
    var curve = new THREE.EllipseCurve(0, 0, 1.002, 1.002, 0, Math.PI * 2, false, 0);
    var points = curve.getPoints(64);
    var geo = new THREE.BufferGeometry().setFromPoints(points);
    var line = new THREE.Line(geo, gridMat);
    line.rotation.y = angle;
    globeGroup.add(line);
  }
  for (var j = -80; j <= 80; j += 20) {
    var phi = (90 - j) * Math.PI / 180;
    var r = Math.sin(phi);
    var y = Math.cos(phi);
    var circleCurve = new THREE.EllipseCurve(0, 0, r, r, 0, Math.PI * 2, false, 0);
    var circlePoints = circleCurve.getPoints(64);
    var circleGeo = new THREE.BufferGeometry().setFromPoints(circlePoints);
    var circleLine = new THREE.Line(circleGeo, gridMat);
    circleLine.position.y = y;
    circleLine.rotation.x = Math.PI / 2;
    globeGroup.add(circleLine);
  }

  globe = globeGroup;
  scene.add(globeGroup);
}

function onWindowResize() {
  updateSize();
}

function updateSize() {
  var w = container.clientWidth;
  var h = container.clientHeight;
  camera.aspect = w / h;
  camera.updateProjectionMatrix();
  renderer.setSize(w, h);
}

function animate() {
  requestAnimationFrame(animate);
  var delta = clock.getDelta();
  if (globe) {
    globe.rotation.y += delta * 0.08;
  }
  // Pulse markers
  var t = clock.getElapsedTime();
  for (var i = 0; i < markers.length; i++) {
    var m = markers[i];
    if (m.pulse && m.pulse.visible) {
      m.pulse.scale.setScalar(1 + Math.sin(t * 3 + i) * 0.3);
      m.pulse.material.opacity = 0.3 + Math.sin(t * 3 + i) * 0.2;
    }
  }
  renderer.render(scene, camera);
}

function onCanvasHover(event) {
  var rect = event.target.getBoundingClientRect();
  mouse.x = ((event.clientX - rect.left) / rect.width) * 2 - 1;
  mouse.y = -((event.clientY - rect.top) / rect.height) * 2 + 1;
  raycaster.setFromCamera(mouse, camera);
  var markerMeshes = markers.map(function(m) { return m.marker; });
  var intersects = raycaster.intersectObjects(markerMeshes);
  if (intersects.length > 0) {
    event.target.style.cursor = 'pointer';
  } else {
    event.target.style.cursor = 'default';
  }
}

function onCanvasClick(event) {
  var rect = event.target.getBoundingClientRect();
  mouse.x = ((event.clientX - rect.left) / rect.width) * 2 - 1;
  mouse.y = -((event.clientY - rect.top) / rect.height) * 2 + 1;
  raycaster.setFromCamera(mouse, camera);
  var markerMeshes = markers.map(function(m) { return m.marker; });
  var intersects = raycaster.intersectObjects(markerMeshes);
  if (intersects.length > 0) {
    var hit = intersects[0].object;
    var idx = markerMeshes.indexOf(hit);
    if (idx !== -1 && markers[idx]) {
      showNewsCard(markers[idx].item);
    }
  }
}

function showNewsCard(item) {
  container.querySelector('#news-headline').textContent = item.title;
  container.querySelector('#news-source').textContent = item.source;
  container.querySelector('#news-date').textContent = item.date || '';
  container.querySelector('#news-description').textContent = item.description || '';
  var linkEl = container.querySelector('#news-link');
  linkEl.href = item.link || '#';
  overlayEl.classList.add('visible');
}

function addMarker(item) {
  var loc = findLocation(item.title, item.description, item.source);
  var pos = latLngToVec3(loc.lat, loc.lng, 1.0);
  var cat = detectCategory(item.title, item.description);
  var color = categoryColors[cat] || categoryColors.other;

  // Main marker (small icosahedron)
  var markerGeo = new THREE.IcosahedronGeometry(0.025, 0);
  var markerMat = new THREE.MeshPhongMaterial({ color: color, emissive: color, emissiveIntensity: 0.5 });
  var markerMesh = new THREE.Mesh(markerGeo, markerMat);
  markerMesh.position.copy(pos);
  globe.add(markerMesh);

  // Pulse ring
  var pulseGeo = new THREE.RingGeometry(0.025, 0.04, 16);
  var pulseMat = new THREE.MeshBasicMaterial({
    color: color,
    transparent: true,
    opacity: 0.3,
    side: THREE.DoubleSide
  });
  var pulseMesh = new THREE.Mesh(pulseGeo, pulseMat);
  pulseMesh.position.copy(pos);
  pulseMesh.lookAt(new THREE.Vector3(0, 0, 0));
  globe.add(pulseMesh);

  markers.push({
    marker: markerMesh,
    pulse: pulseMesh,
    item: item,
    position: pos.clone()
  });
}

async function fetchAndParseFeeds() {
  var feeds = [
    { url: 'https://feeds.bbci.co.uk/news/rss.xml', name: 'BBC' },
    { url: 'https://rss.cnn.com/rss/cnn_topstories.rss', name: 'CNN' },
    { url: 'https://feeds.reuters.com/reuters/worldNews', name: 'Reuters' },
    { url: 'https://www.aljazeera.com/xml/rss/all.xml', name: 'Al Jazeera' },
    { url: 'https://techcrunch.com/feed/', name: 'TechCrunch' },
    { url: 'https://feeds.theguardian.com/theguardian/world/rss', name: 'The Guardian' }
  ];

  var allItems = [];
  var pending = feeds.length;
  var loaded = 0;

  feeds.forEach(function(feed) {
    mica.fetch(feed.url).then(function(response) {
      if (!response.ok) { loaded++; checkDone(); return; }
      response.text().then(function(xmlText) {
        try {
          var parser = new DOMParser();
          var doc = parser.parseFromString(xmlText, 'text/xml');
          var items = doc.querySelectorAll('item');
          items.forEach(function(itemEl) {
            var title = (itemEl.querySelector('title') && itemEl.querySelector('title').textContent) || '';
            var link = (itemEl.querySelector('link') && itemEl.querySelector('link').textContent) || '';
            var desc = (itemEl.querySelector('description') && itemEl.querySelector('description').textContent) || '';
            var pubDate = (itemEl.querySelector('pubDate') && itemEl.querySelector('pubDate').textContent) || '';
            var category = (itemEl.querySelector('category') && itemEl.querySelector('category').textContent) || '';
            if (title && link) {
              allItems.push({
                title: title,
                link: link,
                description: desc.replace(/<[^>]*>/g, '').substring(0, 300),
                source: feed.name,
                date: pubDate ? new Date(pubDate).toLocaleDateString() : '',
                category: category
              });
            }
          });
        } catch(e) {
          console.warn('RSS parse error for', feed.name, e);
        }
        loaded++;
        checkDone();
      }).catch(function(e) { loaded++; checkDone(); });
    }).catch(function(e) { loaded++; checkDone(); });
  });

  function checkDone() {
    if (loaded >= pending) {
      newsItems = allItems;
      renderMarkers();
    }
  }
}

function renderMarkers() {
  // Clear old markers
  for (var i = 0; i < markers.length; i++) {
    globe.remove(markers[i].marker);
    globe.remove(markers[i].pulse);
  }
  markers = [];

  // Add new markers (limit to avoid clutter)
  var maxMarkers = 80;
  var shown = 0;
  for (var i = 0; i < newsItems.length && shown < maxMarkers; i++) {
    addMarker(newsItems[i]);
    shown++;
  }

  // Hide loading
  if (loadingEl) loadingEl.classList.add('hidden');
}

init();
